import logo from './logo.svg';
import './App.css';
import Home from './Page/Home';
import Buy from './Page/Buy';
import { BrowserRouter, Routes, Route } from 'react-router-dom'; // Updated import
import Contact from './Page/Contact';
import Pet from './Page/Pet';
import Service from './Page/Service';
import Clinic from './Page/Clinic';
import Product from './Page/Product';
import Cart from './Page/Cart';
import Checkout from './Page/Checkout';
import { Elements } from '@stripe/react-stripe-js';
import { loadStripe } from '@stripe/stripe-js';

const stripePromise = loadStripe('pk_test_51OrcLQSAiyHNro1f1wASApovQVKrIIsimbl9F2W9uEWJzZqECYEuy7weFFmWGw27h724YwlV9LDRQkOwzoKbss8i00s2tVwEiA');

function App() {
  return (
    <BrowserRouter>
        <Routes>
          <Route path='/' element={<Home />} />
          <Route path='/clinic' element={<Clinic />} />
          <Route path='/contact' element={<Contact />} />
          <Route path='/pet' element={<Pet />} />
          <Route path='/service' element={<Service />} />
          <Route path='/buy' element={<Buy />} />
          <Route path='/product' element={<Product />} />
          <Route path='/cart' element={<Cart />} />
          <Route path='/checkout' element={<Checkout />} />
        </Routes>
    </BrowserRouter>
  );
}

export default App;
